    42→const listeners = new Set<() => void>();
    43→function notify() { listeners.forEach(fn => { try { fn(); } catch {} }); }
    44→
    45→// ── Concurrency lock (shared via SyncLock) ────────────────────────────────────
    46→
    47→export const SyncQueueService = {
    48→
    49→  // FIX 1: subscribe/unsubscribe for push-based queue updates.
    50→  subscribe(fn: () => void): () => void {
    51→    listeners.add(fn);
    52→    return () => listeners.delete(fn);
    53→  },
