const handleGstFetch = async () => {
  if (firm.gstin.length !== 15) return;
  setGstFetching(true);
  setGstFetchError('');
  setGstFetchResult(null);
  try {
    const res = await GSTService.fetchDetails(firm.gstin.toUpperCase());
    const legalName = res.legalName || '';
    const tradeName = res.tradeName || '';
    const address   = res.address   || '';
    const state     = res.state     || '';
    const city      = (res as any).city || '';

    // tradeName = the business/shop name → goes into firm_name
    // legalName = the registered owner's name → goes into owner_name
    // If only legalName exists (no tradeName), use it for firm_name too
    const firmName  = tradeName || legalName;
    const ownerName = legalName;

    const filled: string[] = [];
    setFirm(prev => {
      const next = { ...prev };
      if (firmName)  { next.firm_name  = firmName;  filled.push('Business Name'); }
      if (ownerName) { next.owner_name = ownerName; filled.push('Owner Name'); }
      if (address)   { next.address    = address;   filled.push('Address'); }
      if (state)     { next.state      = state;     filled.push('State'); }
      if (city)      { next.city       = city;      filled.push('City'); }
      return next;
    });
    setGstFetchResult({ ...res, legalName: firmName, filledFields: filled });
  } catch (e: any) {
    setGstFetchError(e.message || 'Could not fetch GST details.');
  } finally {
    setGstFetching(false);
  }
};

