const WRITE_TIMEOUT_MS = 15_000;

function withWriteTimeout<T>(promise: Promise<T>): Promise<T> {
  return Promise.race([
    promise,
    new Promise<T>((_, reject) =>
      setTimeout(() => {
        const err: any = new Error(
          'Firestore write timed out — IndexedDB may be locked (Android WebView memory pressure). Falling back to offline queue.',
        );
        err.code = 'WRITE_TIMEOUT';
        reject(err);
      }, WRITE_TIMEOUT_MS),
    ),
  ]);
}

