    18→// FIX: Audit logging is fire-and-forget.  The old implementation awaited every
    19→// audit write inside add/update/delete, which:
    20→//   (a) doubled the perceived latency for every write operation, and
    21→//   (b) doubled Firestore write costs on every mutation.
    22→//
    23→// Audit logs are non-critical — a failure to record an audit entry should never
    24→// block or error the primary operation.  We fire the log asynchronously and
    25→// swallow any rejection (AuditService.log already swallows internally, but the
    26→// outer await was still forcing a serial round-trip).
    27→function auditAsync(...args: Parameters<typeof AuditService.log>) {
    28→  AuditService.log(...args).catch(() => { /* intentionally swallowed */ });
    29→}
    30→
    31→/**
    32→ * WRITE TIMEOUT GUARD
    33→ * ─────────────────────────────────────────────────────────────────────────────
    34→ * On Android WebView under memory pressure, Firestore's persistentLocalCache
    35→ * writes to IndexedDB can hang indefinitely — the Promise never resolves AND
    36→ * never rejects. This leaves any UI that does `setLoading(true)` → `await write`
    37→ * → `setLoading(false)` frozen on "Saving…" forever.
    38→ *
    39→ * This wrapper races every write against a hard 15-second timeout. If the
    40→ * timeout fires first we reject with a structured WRITE_TIMEOUT error so the
    41→ * caller can fall back to the offline sync-queue instead of hanging the UI.
    42→ * 15 s is generous — a healthy IndexedDB write resolves in < 500 ms.
    43→ */
    44→const WRITE_TIMEOUT_MS = 30_000;
    45→
    46→function withWriteTimeout<T>(promise: Promise<T>): Promise<T> {
    47→  return Promise.race([
    48→    promise,
    49→    new Promise<T>((_, reject) =>
    50→      setTimeout(() => {
    51→        const err: any = new Error(
    52→          'Save timed out — queued for background sync.',
    53→        );
    54→        err.code = 'WRITE_TIMEOUT';
    55→        reject(err);
    56→      }, WRITE_TIMEOUT_MS),
    57→    ),
    58→  ]);
    59→}
    60→
    61→/**
    62→ * Recursively removes undefined values from an object so Firestore never
    63→ * receives `undefined` fields (which it rejects with an error).
    64→ */
    65→function sanitizeForFirestore(obj: any): any {
    66→  if (obj === null || obj === undefined) return obj;
    67→  if (Array.isArray(obj)) return obj.map(sanitizeForFirestore);
    68→  if (typeof obj === 'object' && !(obj instanceof Date)) {
