     1→/**
     2→ * SyncQueueService  — simple offline queue backed by localStorage.
     3→ *
     4→ * CONTEXT: The codebase has three independent sync systems
     5→ * (SyncQueueService, OfflineSyncService, OfflineQueueService).
     6→ * The full architectural consolidation is a larger refactor; in the
     7→ * meantime this file fixes the specific bugs reported:
     8→ *
     9→ * FIX 1: Added a lightweight subscribe/notify mechanism so consumers
    10→ *   (useSyncStatus) can react to queue changes via a push callback
    11→ *   instead of polling localStorage every second with setInterval.
    12→ *
    13→ * FIX 2: processQueue() now uses a module-level lock flag to prevent
    14→ *   concurrent invocations.  Previously, if both SyncQueueService and
    15→ *   OfflineSyncService fired on the 'online' event simultaneously, the
    16→ *   same queue items could be written to Firestore twice, creating
    17→ *   duplicate records.
    18→ */
    19→
    20→import { ApiService } from './api';
    21→import { SyncLock } from './syncLock';
    22→import { perfMonitor } from '../utils/perfMonitor';
    23→
    24→export interface QueueItem {
    25→  id: string;
    26→  userId: string;
    27→  operation: 'create' | 'update' | 'delete';
    28→  collection: string;
    29→  docId?: string;
    30→  data: any;
    31→  timestamp: number;
    32→  priority: 'high' | 'normal' | 'low';
    33→  retries: number;
    34→  maxRetries: number;
    35→  error?: string;
    36→}
    37→
    38→const QUEUE_KEY  = 'offline_sync_queue';
    39→const MAX_RETRIES = 3;
    40→
    41→// ── Push-subscription registry ────────────────────────────────────────────────
    42→const listeners = new Set<() => void>();
    43→function notify() { listeners.forEach(fn => { try { fn(); } catch {} }); }
    44→
    45→// ── Concurrency lock (shared via SyncLock) ────────────────────────────────────
    46→
    47→export const SyncQueueService = {
    48→
    49→  // FIX 1: subscribe/unsubscribe for push-based queue updates.
    50→  subscribe(fn: () => void): () => void {
    51→    listeners.add(fn);
    52→    return () => listeners.delete(fn);
    53→  },
    54→
    55→  addToQueue(
    56→    userId: string,
    57→    operation: 'create' | 'update' | 'delete',
    58→    collection: string,
    59→    data: any,
    60→    docId?: string,
    61→    priority: 'high' | 'normal' | 'low' = 'normal',
    62→  ): QueueItem {
    63→    const item: QueueItem = {
    64→      id: `${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
    65→      userId,
    66→      operation,
    67→      collection,
    68→      docId,
    69→      data,
    70→      timestamp: Date.now(),
    71→      priority,
    72→      retries: 0,
    73→      maxRetries: MAX_RETRIES,
    74→    };
    75→
    76→    const queue = SyncQueueService.getQueue();
    77→    queue.push(item);
    78→    localStorage.setItem(QUEUE_KEY, JSON.stringify(queue));
    79→    notify();
    80→    return item;

