    85→            }
    86→            // --- ADDRESS FIX END ---
    87→
    88→            // Derive state from multiple fallback sources:
    89→            // 1. Direct field (some API variants)
    90→            // 2. data.stj = "State - Maharashtra,Zone - ..." (this API's format)
    91→            // 3. First 2 digits of GSTIN → state code table (always available)
    92→            const stateFromStj = data.stj
    93→                ? (data.stj.match(/^State\s*-\s*([^,]+)/i)?.[1]?.trim() || '')
    94→                : '';
    95→            const stateFromCode = GSTIN_STATE_CODES[gstin.substring(0, 2)] || '';
    96→            const state = data.state || (data.pradr?.addr?.stcd) || stateFromStj || stateFromCode;
    97→
    98→            // Extract city: prefer pradr.addr.dst (district) → loc (locality) → parse from adr
    99→            let city = '';
   100→            if (data.pradr?.addr?.dst) {
