   104→            } else if (address) {
   105→                // Parse from adr string: typically "door, street, locality, district, state, pin"
   106→                const parts = address.split(',').map((s: string) => s.trim()).filter(Boolean);
   107→                if (parts.length >= 3) {
   108→                    // Walk back from end: skip pincode (all digits) and state, take first valid part
   109→                    for (let i = parts.length - 1; i >= 0; i--) {
   110→                        const p = parts[i];
   111→                        if (/^\d+$/.test(p)) continue; // skip pincode
   112→                        const stateLC = state.toLowerCase();
   113→                        if (stateLC && p.toLowerCase().includes(stateLC.split(' ')[0])) continue; // skip state
   114→                        city = p;
   115→                        break;
   116→                    }
   117→                }
   118→            }
