     1→import { parseDateSafe, toDateStrSafe } from './dateUtils';
     2→
     3→export interface AutoPaymentInfo {
     4→  txId: string;
     5→  date: string;
     6→  amount: number;
     7→}
     8→
     9→export interface OrderPaymentStatus {
    10→  orderId: string;
    11→  orderTotal: number;
    12→  directPaid: number;
    13→  autoPaid: number;
    14→  totalPaid: number;
    15→  balance: number;
    16→  status: 'paid' | 'partial' | 'pending';
    17→  autoPayments: AutoPaymentInfo[];
    18→}
    19→
    20→function parseDate(raw: any): Date {
    21→  return parseDateSafe(raw);
    22→}
    23→
    24→function toDateStr(raw: any): string {
    25→  return toDateStrSafe(raw);
    26→}
    27→
    28→const round2 = (n: number) => Math.round(n * 100) / 100;
    29→
    30→export function computePaymentDistribution(
    31→  orders: any[],
    32→  transactions: any[],
    33→  autoDistribute: boolean = true
    34→): Map<string, OrderPaymentStatus> {
    35→  const result = new Map<string, OrderPaymentStatus>();
    36→
    37→  for (const order of orders) {
    38→    if (!order.id) continue;
    39→    result.set(order.id, {
    40→      orderId: order.id,
    41→      orderTotal: Number(order.total_amount) || 0,
    42→      directPaid: 0,
    43→      autoPaid: 0,
    44→      totalPaid: 0,
    45→      balance: 0,
    46→      status: 'pending',
    47→      autoPayments: [],
    48→    });
    49→  }
    50→
    51→  // Step 1: Apply directly linked transactions (by bill_no match on the order)
    52→  const usedTransactionIds = new Set<string>();
    53→
    54→  for (const tx of transactions) {
    55→    if (!tx.bill_no || !tx.id) continue;
    56→    const billNo = String(tx.bill_no).trim();
    57→
    58→    const linkedOrder = orders.find(o => {
    59→      const refNo = String(o.invoice_no || o.bill_no || '').trim();
    60→      if (!refNo || refNo !== billNo) return false;
    61→      if (tx.type === 'received' && o.type !== 'sell') return false;
    62→      if (tx.type === 'paid' && o.type !== 'purchase') return false;
    63→      return true;
    64→    });
    65→
    66→    if (!linkedOrder || !result.has(linkedOrder.id)) continue;
    67→    result.get(linkedOrder.id)!.directPaid = round2(result.get(linkedOrder.id)!.directPaid + (Number(tx.amount) || 0));
    68→    usedTransactionIds.add(tx.id);
    69→  }
    70→
    71→  // Step 2: Auto-distribute unlinked payments FIFO by party+type
    72→  if (autoDistribute) {
    73→    // Group orders by (party_name :: order_type), sorted FIFO
    74→    const groupedOrders = new Map<string, any[]>();
    75→    for (const order of orders) {
    76→      const key = `${order.party_name || ''}::${order.type || ''}`;
    77→      if (!groupedOrders.has(key)) groupedOrders.set(key, []);
    78→      groupedOrders.get(key)!.push(order);
    79→    }
    80→    for (const [, arr] of groupedOrders) {
    81→      arr.sort((a, b) => parseDate(a.date).getTime() - parseDate(b.date).getTime());
    82→    }
    83→
    84→    // Group unlinked transactions by (party_name :: matching_order_type), sorted by date
    85→    const groupedTxs = new Map<string, any[]>();
    86→    for (const tx of transactions) {
    87→      if (usedTransactionIds.has(tx.id)) continue;
    88→      const orderType = tx.type === 'received' ? 'sell' : 'purchase';
    89→      const key = `${tx.party_name || ''}::${orderType}`;
    90→      if (!groupedTxs.has(key)) groupedTxs.set(key, []);
    91→      groupedTxs.get(key)!.push(tx);
    92→    }
    93→    for (const [, arr] of groupedTxs) {
    94→      arr.sort((a, b) => parseDate(a.date).getTime() - parseDate(b.date).getTime());
    95→    }
    96→
    97→    for (const [key, pOrders] of groupedOrders) {
    98→      const txs = groupedTxs.get(key);
    99→      if (!txs || txs.length === 0) continue;
   100→
   101→      // Track remaining per-transaction
   102→      const txRemaining = txs.map(tx => ({
   103→        tx,
   104→        remaining: Number(tx.amount) || 0,
   105→      }));
   106→
   107→      for (const order of pOrders) {
   108→        const status = result.get(order.id)!;
   109→        let orderPending = status.orderTotal - status.directPaid - status.autoPaid;
   110→        if (orderPending <= 0) continue;
   111→
   112→        for (const txInfo of txRemaining) {
   113→          if (txInfo.remaining <= 0) continue;
   114→          if (orderPending <= 0) break;
   115→
   116→          const applied = round2(Math.min(txInfo.remaining, orderPending));
   117→          txInfo.remaining = round2(txInfo.remaining - applied);
   118→          orderPending = round2(orderPending - applied);
   119→          status.autoPaid = round2(status.autoPaid + applied);
   120→          status.autoPayments.push({
   121→            txId: txInfo.tx.id || '',
   122→            date: toDateStr(txInfo.tx.date),
   123→            amount: applied,
   124→          });
   125→        }
   126→      }
   127→    }
   128→  }
   129→
   130→  // Step 3: Compute final status
   131→  for (const [, status] of result) {
   132→    status.totalPaid = round2(status.directPaid + status.autoPaid);
   133→    status.balance = round2(status.orderTotal - status.totalPaid);
   134→    if (status.totalPaid >= status.orderTotal) {
   135→      status.status = 'paid';
   136→    } else if (status.totalPaid > 0) {
   137→      status.status = 'partial';
   138→    } else {
   139→      status.status = 'pending';
   140→    }
   141→  }
   142→
   143→  return result;
   144→}
