    78→export const calculateAccounting = (
    79→    ledger: any[],
    80→    transactions: any[],
    81→    role: string,
    82→    opts?: {
    83→        openingBalance?: number;
    84→        openingBalanceType?: 'they_owe' | 'we_owe';
    85→        miscCharges?: any[];
    86→    }
    87→) => {
    88→    let totalBilled = 0;
    89→    let totalPaid = 0;
    90→
    91→    ledger.forEach(l => {
    92→        if((role === 'customer' && l.type === 'sell') || (role === 'supplier' && l.type === 'purchase')) {
    93→            totalBilled += (Number(l.total_amount) || 0);
    94→        }
    95→    });
    96→
    97→    transactions.forEach(t => {
    98→        if((role === 'customer' && t.type === 'received') || (role === 'supplier' && t.type === 'paid')) {
    99→            totalPaid += (Number(t.amount) || 0);
   100→        }
   101→    });
   102→
   103→    const ob = Number(opts?.openingBalance) || 0;
   104→    const openingEffect = ob > 0
   105→        ? (opts?.openingBalanceType === 'we_owe' ? -ob : ob)
   106→        : 0;
   107→
   108→    let miscNet = 0;
   109→    (opts?.miscCharges || []).forEach((c: any) => {
   110→        if (c.direction === 'charge_to_party') miscNet += (Number(c.amount) || 0);
   111→        else miscNet -= (Number(c.amount) || 0);
   112→    });
   113→
   114→    return {
   115→        totalBilled,
   116→        totalPaid,
   117→        balance: totalBilled - totalPaid + openingEffect + miscNet,
   118→        openingEffect,
   119→        miscNet,
   120→    };
   121→};
